import { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { supabase } from '@/lib/supabase'
import { useFilterStore, type Category } from '@/store/useFilterStore'

// Themen-Grid auf der Home-Page laut CLAUDE.md §1.
//
// Statt einer hardcoded Liste laden wir Counts aus vocab_medical und
// rendern jede vorhandene Kategorie (außer "unsorted") als Kachel.
// Klick auf eine Kachel setzt den Kategorie-Filter und leitet zu den
// Flashcards weiter.

type Counts = Record<string, number>

const TILE_META: Record<Exclude<Category, 'all'>, { emoji: string; label: string; color: string }> = {
  anamnese:     { emoji: '🩺', label: 'Anamnese',     color: 'var(--red)' },
  anatomie:     { emoji: '🫀', label: 'Anatomie',     color: 'var(--green)' },
  symptome:     { emoji: '🤒', label: 'Symptome',     color: 'var(--orange)' },
  krankheiten:  { emoji: '🦠', label: 'Krankheiten',  color: 'var(--red)' },
  pharma:       { emoji: '💊', label: 'Pharma',       color: 'var(--lg)' },
  untersuchung: { emoji: '🔬', label: 'Untersuchung', color: 'var(--green)' },
  gynaekologie: { emoji: '🤰', label: 'Gynäkologie',  color: 'var(--orange)' },
  verb:         { emoji: '⚡', label: 'Verben',       color: 'var(--yellow)' },
  adjektiv:     { emoji: '🎨', label: 'Adjektive',    color: 'var(--lg)' },
  phrase:       { emoji: '💬', label: 'Phrasen',      color: 'var(--red)' }
}

const ORDER: Array<keyof typeof TILE_META> = [
  'anamnese',
  'anatomie',
  'symptome',
  'krankheiten',
  'pharma',
  'untersuchung',
  'gynaekologie',
  'verb',
  'adjektiv',
  'phrase'
]

export function ThemeGrid() {
  const [counts, setCounts] = useState<Counts | null>(null)
  const setCategory = useFilterStore((s) => s.setCategory)
  const navigate = useNavigate()

  useEffect(() => {
    let cancelled = false

    async function load() {
      // Im MVP holen wir alle Kategorien clientseitig — 440 Rows ist OK,
      // GROUP BY würde eine RPC erfordern (Schema-Erweiterung).
      const { data, error } = await supabase
        .from('vocab_medical')
        .select('category')

      if (cancelled || error) return
      const c: Counts = {}
      for (const row of (data ?? []) as Array<{ category: string | null }>) {
        if (!row.category || row.category === 'unsorted') continue
        c[row.category] = (c[row.category] ?? 0) + 1
      }
      setCounts(c)
    }

    void load()
    return () => { cancelled = true }
  }, [])

  function handleClick(cat: Category) {
    setCategory(cat)
    navigate('/learn/medical/flashcards')
  }

  return (
    <div
      style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fill, minmax(140px, 1fr))',
        gap: '0.7rem'
      }}
    >
      {ORDER.map((key) => {
        const count = counts?.[key] ?? 0
        const meta = TILE_META[key]
        const loading = counts === null
        const empty = !loading && count === 0

        return (
          <button
            key={key}
            disabled={empty}
            onClick={() => handleClick(key)}
            style={{
              background: 'var(--white)',
              border: `2px solid ${meta.color}`,
              borderRadius: 14,
              padding: '0.85rem',
              boxShadow: 'var(--shadow-card)',
              cursor: empty ? 'default' : 'pointer',
              textAlign: 'left',
              fontFamily: 'inherit',
              opacity: empty ? 0.4 : 1,
              transition: 'transform 100ms ease-out',
              minHeight: 110,
              display: 'flex',
              flexDirection: 'column',
              gap: 6
            }}
          >
            <div style={{ fontSize: '1.7rem', lineHeight: 1 }} aria-hidden="true">{meta.emoji}</div>
            <div style={{ fontFamily: 'Georgia, serif', fontWeight: 700, fontSize: '0.95rem', color: meta.color }}>
              {meta.label}
            </div>
            <div style={{ fontSize: '0.75rem', opacity: 0.65 }}>
              {loading ? '…' : empty ? 'leer' : `${count} ${count === 1 ? 'Karte' : 'Karten'}`}
            </div>
          </button>
        )
      })}
    </div>
  )
}
