import { useEffect, useState } from 'react'
import { supabase } from '@/lib/supabase'
import { useAuthStore } from '@/store/useAuthStore'

// StreakBox laut CLAUDE.md §3.
//
// Verhalten:
//   1. Bei Mount → ruft die Postgres-Funktion update_streak() auf — die
//      bestimmt timezone-safe (UTC date), ob der Streak fortgesetzt wird,
//      pausiert wird (Streak-Freeze) oder bei 0 startet.
//   2. Lädt danach profiles.current_streak / longest_streak und zeigt sie an.
//
// Multiplikator-Anzeige (CLAUDE.md §8 Streak-Multiplikator):
//   1–6 → ×1.0, 7–29 → ×1.2, 30–99 → ×1.5, 100+ → ×2.0
function streakMultiplier(streak: number): string {
  if (streak >= 100) return '×2.0'
  if (streak >= 30) return '×1.5'
  if (streak >= 7) return '×1.2'
  return '×1.0'
}

export function StreakBox() {
  const { user } = useAuthStore()
  const [current, setCurrent] = useState<number | null>(null)
  const [longest, setLongest] = useState<number | null>(null)

  useEffect(() => {
    if (!user) return
    let cancelled = false

    async function load() {
      // 1) Streak via RPC aktualisieren (idempotent, mehrmals täglich OK)
      await supabase.rpc('update_streak', { p_user_id: user!.id })

      // 2) Profile-Werte lesen
      const { data } = await supabase
        .from('profiles')
        .select('current_streak, longest_streak')
        .eq('id', user!.id)
        .single()

      if (cancelled || !data) return
      setCurrent(data.current_streak ?? 0)
      setLongest(data.longest_streak ?? 0)
    }

    void load()
    return () => { cancelled = true }
  }, [user])

  const days = current ?? 0
  const isHot = days >= 7

  return (
    <div
      style={{
        background: 'var(--white)',
        border: `2px solid ${isHot ? 'var(--orange)' : 'var(--green)'}`,
        borderRadius: 14,
        padding: '0.9rem 1.1rem',
        boxShadow: 'var(--shadow-card)',
        display: 'flex',
        alignItems: 'center',
        gap: '0.9rem'
      }}
    >
      <div style={{ fontSize: '2rem', lineHeight: 1 }} aria-hidden="true">
        {isHot ? '🔥' : '🌱'}
      </div>
      <div style={{ flex: 1 }}>
        <div style={{ fontFamily: 'Georgia, serif', fontWeight: 700, fontSize: '1.4rem', color: 'var(--red)' }}>
          {current === null ? '…' : `${days} ${days === 1 ? 'Tag' : 'Tage'}`}
        </div>
        <div style={{ fontSize: '0.78rem', opacity: 0.7 }}>
          {longest !== null && longest > 0 && `Bestleistung: ${longest} Tage · `}
          XP-Multi {streakMultiplier(days)}
        </div>
      </div>
    </div>
  )
}
