import { useNavigate } from 'react-router-dom'

// Horizontaler Scroll mit allen 8 Spielmodi laut CLAUDE.md §6.
// Alle bis auf Sprint-zukünftige sind als "coming-soon" disabled.

type Mode = {
  emoji: string
  title: string
  subtitle: string
  to: string
  available: boolean
  color: string
}

const MODES: Mode[] = [
  { emoji: '🃏', title: 'Karteikarten',  subtitle: 'SRS · SM-2',         to: '/learn/medical/flashcards',     available: true,  color: 'var(--red)' },
  { emoji: '🔗', title: 'Wörterpaare',    subtitle: 'Matching',           to: '/learn/medical/matching',       available: true,  color: 'var(--green)' },
  { emoji: '🧩', title: 'Satzreihenfolge', subtitle: 'HU arrangieren',    to: '/learn/medical/ordering',       available: true,  color: 'var(--orange)' },
  { emoji: '⏱️', title: 'Speedround',    subtitle: '60s · Combo',        to: '/learn/medical/speedround',     available: true,  color: 'var(--red)' },
  { emoji: '✅', title: 'Multiple Choice', subtitle: '10 Fragen',         to: '/learn/medical/quiz',           available: true,  color: 'var(--lg)' },
  { emoji: '⌨️', title: 'Tippen',         subtitle: 'Aktiv schreiben',    to: '/learn/medical/vocab-trainer',  available: true,  color: 'var(--green)' },
  { emoji: '⚡', title: 'Verben',         subtitle: '5 Tempora',          to: '/learn/medical/verb-trainer',   available: true,  color: 'var(--yellow)' },
  { emoji: '🔁', title: 'Synonyme',       subtitle: 'HU ↔ HU',            to: '/learn/medical/synonym-match',  available: true,  color: 'var(--orange)' }
]

export function GameModeScroll() {
  const navigate = useNavigate()

  return (
    <div
      style={{
        display: 'flex',
        gap: '0.7rem',
        overflowX: 'auto',
        paddingBottom: '0.5rem',
        scrollSnapType: 'x mandatory',
        WebkitOverflowScrolling: 'touch'
      }}
    >
      {MODES.map((m) => (
        <button
          key={m.to}
          disabled={!m.available}
          onClick={() => m.available && navigate(m.to)}
          style={{
            flex: '0 0 auto',
            width: 130,
            minHeight: 130,
            background: 'var(--white)',
            border: `2px solid ${m.color}`,
            borderRadius: 14,
            padding: '0.8rem',
            boxShadow: 'var(--shadow-card)',
            cursor: m.available ? 'pointer' : 'default',
            textAlign: 'left',
            fontFamily: 'inherit',
            opacity: m.available ? 1 : 0.55,
            scrollSnapAlign: 'start',
            display: 'flex',
            flexDirection: 'column',
            gap: 4,
            position: 'relative'
          }}
        >
          <div style={{ fontSize: '1.6rem', lineHeight: 1 }} aria-hidden="true">{m.emoji}</div>
          <div style={{ fontFamily: 'Georgia, serif', fontWeight: 700, fontSize: '0.85rem', color: m.color }}>
            {m.title}
          </div>
          <div style={{ fontSize: '0.7rem', opacity: 0.65 }}>{m.subtitle}</div>
          {!m.available && (
            <div
              style={{
                position: 'absolute',
                top: 6,
                right: 6,
                fontSize: '0.6rem',
                background: 'var(--cream)',
                border: '1px solid rgba(0,0,0,0.1)',
                borderRadius: 6,
                padding: '1px 5px',
                opacity: 0.85
              }}
            >
              bald
            </div>
          )}
        </button>
      ))}
    </div>
  )
}
